if doc.custom_document and doc.custom_document_value:

    # If links table is empty, create a new row
    if not doc.links:
        row = doc.append("links", {})

        row.link_doctype = doc.custom_document
        row.link_name = doc.custom_document_value
        row.link_title = doc.custom_document_value

    else:
        # Update all existing link rows
        for row in doc.links:
            row.link_doctype = doc.custom_document
            row.link_name = doc.custom_document_value
            row.link_title = doc.custom_document_value

# Mark Dealer created (1)
if doc.from_document:
    frappe.db.set_value("Lead", doc.from_document, "custom_dealer_created", 1)

# Reset Dealer created flag (0)
if doc.from_document:
    frappe.db.set_value("Lead", doc.from_document, "custom_dealer_created", 0)

# Mark Farmer created (1)
if doc.from_document:
    frappe.db.set_value("Lead", doc.from_document, "custom_farmer_created", 1)

# Reset Farmer created flag (0)
if doc.from_document:
    frappe.db.set_value("Lead", doc.from_document, "custom_farmer_created", 0)

def rename_user_id(doc, method):
    # if email is being used as name, rename it
    if doc.name != doc.username:
        frappe.rename_doc(
            doctype="User",
            old=doc.name,
            new=doc.username,
            force=True,
            merge=False
        )

def get_customer_from_user(user_id):
    cu = frappe.db.get_value("Portal User", {"user": user_id}, "parent")
    return cu

def get_registration_details(customer):
    reg_type = frappe.db.get_value("Customer", customer, "custom_document_type")
    reg_value = frappe.db.get_value("Customer", customer, "custom_document_value")
    if reg_type and reg_value:
        return frappe.get_doc(reg_type, reg_value)
    return None

def before_save(doc, method):
    if not doc.user_id:
        return

    customer = get_customer_from_user(doc.user_id)
    if not customer:
        frappe.throw("No Customer found for this User ID")

    doc.customer_id = customer
    doc.customer_name = frappe.db.get_value("Customer", customer, "customer_name")

    reg = get_registration_details(customer)

    if reg:
        doc.state = reg.state
        doc.district = reg.district
        doc.tahshil = reg.tahshil

# -------- Dealer Registration: Block Submit If Not Completed --------

if not doc.is_completed:
    frappe.throw("Please complete all required fields before submitting the form.")

# Auto-submit Apply Dealership when status becomes Active

if doc.approval_status == "Active" and doc.docstatus == 0:
    doc.docstatus = 1

user = doc.user
price_list = doc.price_list

if not user:
    frappe.throw("User is missing")

# ------------------------------------------------
# 1) DELETE ONLY THE PERMISSION CREATED BY THIS DOC
#    (safe: won't delete permissions created manually/elsewhere)
# ------------------------------------------------
to_delete = frappe.get_all(
    "User Permission",
    filters={
        "user": user,
        "allow": "Price List",
        "for_value": price_list,
        "custom_document_from": "Brand Access",
        "custom_document_id": doc.name,
    },
    pluck="name"
)

for name in to_delete:
    frappe.delete_doc("User Permission", name, ignore_permissions=True, force=True)

if to_delete:
    frappe.msgprint(f"Removed Price List Access: {user} → {price_list}")
else:
    frappe.msgprint(f"No tagged permission found to remove for {user} → {price_list}")

# ------------------------------------------------
# 2) OPTIONAL: RESTORE DEFAULT "None" PRICE LIST PERMISSION
#    Only do this if your rule says dealer must have 'None' when no access exists.
# ------------------------------------------------
has_any_price_list_perm = frappe.db.exists(
    "User Permission",
    {"user": user, "allow": "Price List"}
)

if not has_any_price_list_perm:
    none_exists = frappe.db.exists(
        "User Permission",
        {"user": user, "allow": "Price List", "for_value": "None"}
    )

    if not none_exists:
        frappe.get_doc({
            "doctype": "User Permission",
            "user": user,
            "allow": "Price List",
            "for_value": "None",
            "apply_to_all_doctypes": 1,
            "custom_document_from": "Brand Access",
            "custom_document_id": doc.name
        }).insert(ignore_permissions=True)

        frappe.msgprint(f"Restored default None Price List for {user}")
